const createAdvancedTest = (dayNum, title, questions) => questions;

const DAY_51_TEST = createAdvancedTest(51, 'Advance Level Sentences Part 1', [
  { id:'d51-t001', hindi:'Complex sentence = Main clause + ?', options:['Another main clause','Subordinate clause','Simple sentence','Question'], correct:1, explanation:'Complex sentence = main clause + one or more subordinate/dependent clauses.', type:'mcq', difficulty:'easy', marks:1 },
  { id:'d51-t002', hindi:'Compound sentence structure:', options:['Two or more independent clauses joined by coordinating conjunction','Main + subordinate clause','Only one clause','No conjunction'], correct:0, explanation:'Compound = two or more independent clauses joined by coordinating conjunctions (and/but/or/so).', type:'mcq', difficulty:'easy', marks:1 },
  { id:'d51-t003', hindi:'Compound-Complex sentence:', options:['Two simple sentences','Two or more independent clauses + at least one subordinate clause','Only subordinate clauses','Simple + question'], correct:1, explanation:'Compound-Complex = 2+ independent clauses AND 1+ subordinate clause. Most complex type.', type:'mcq', difficulty:'medium', marks:2 },
  { id:'d51-t004', hindi:'Identify COMPLEX sentence:', options:['She is smart and she is kind.','She left because she was tired.','She left; he stayed.','She left. She was tired.'], correct:1, explanation:'"She left because she was tired." — "because" introduces subordinate clause. Complex sentence.', type:'mcq', difficulty:'easy', marks:1 },
  { id:'d51-t005', hindi:'Identify COMPOUND sentence:', options:['She is smart because she studies.','She studies when she can.','She studies hard, and she always succeeds.','Although she studied, she failed.'], correct:2, explanation:'"She studies hard, and she always succeeds." — two independent clauses joined by "and." Compound.', type:'mcq', difficulty:'easy', marks:1 },
  { id:'d51-t006', hindi:'Relative clause: "The man ___ lives next door is a doctor."', options:['which','who','whom','what'], correct:1, explanation:'"The man who lives next door is a doctor." — "who" for people in relative clauses.', type:'fill-blank', difficulty:'easy', marks:1 },
  { id:'d51-t007', hindi:'Relative clause: "The book ___ I borrowed was interesting."', options:['who','whom','which/that','what'], correct:2, explanation:'"The book which/that I borrowed was interesting." — "which/that" for things.', type:'fill-blank', difficulty:'easy', marks:1 },
  { id:'d51-t008', hindi:'Defining vs Non-defining relative clauses:', options:['Same','Defining = essential info (no commas); Non-defining = extra info (commas)','Non-defining = essential; Defining = extra','No difference'], correct:1, explanation:'"The student who works hard wins." (defining — essential). "Ram, who is my friend, won." (non-defining — extra info with commas).', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d51-t009', hindi:'"That" can be used in which type of relative clause?', options:['Only non-defining','Only defining (not with commas)','Both types','Neither'], correct:1, explanation:'"That" is only used in DEFINING relative clauses. Never in non-defining clauses.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d51-t010', hindi:'Inversion: "Never ___ I seen such beauty."', options:['have','had','was','did'], correct:1, explanation:'"Never had I seen such beauty." — negative inversion: Never + past perfect inversion for emphasis.', type:'fill-blank', difficulty:'hard', marks:3 },
  { id:'d51-t011', hindi:'Cleft sentence: "It was Rahul ___ fixed the car."', options:['who','which','that','whom'], correct:2, explanation:'"It was Rahul that/who fixed the car." — Cleft sentence for emphasis. "It was + focus + that/who."', type:'fill-blank', difficulty:'hard', marks:3 },
  { id:'d51-t012', hindi:'"What I need is rest." — sentence type:', options:['Simple','Cleft/Pseudo-cleft (emphasis on "rest")','Compound','Question'], correct:1, explanation:'"What I need is rest." — pseudo-cleft. "What I need" is the focus clause emphasizing "rest."', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d51-t013', hindi:'Conditional sentence type: "If I had money, I would travel."', options:['First conditional','Second conditional (unreal present)','Third conditional','Zero conditional'], correct:1, explanation:'"If I had money, I would travel." — 2nd conditional. Unreal present/future condition.', type:'mcq', difficulty:'medium', marks:2 },
  { id:'d51-t014', hindi:'Zero conditional: "If water ___ to 100°C, it ___." (boil)', options:['heats / boils','heated / boiled','will heat / will boil','heats / boiled'], correct:0, explanation:'"If water heats to 100°C, it boils." — Zero conditional = general truth. Both clauses present simple.', type:'fill-blank', difficulty:'medium', marks:2 },
  { id:'d51-t015', hindi:'Mixed conditional: "If I had studied harder, I would be successful now."', options:['1st conditional','2nd conditional','3rd conditional','Mixed (past condition + present result)'], correct:3, explanation:'Mixed conditional = past hypothetical condition + present result. If + Past Perfect + Would + V1.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d51-t016', hindi:'"Had she known, she would have told us." — inverted conditional:',options:['Simple conditional','Inverted/formal conditional (had + subject + V3)','Question','Command'], correct:1, explanation:'"Had she known" = formal inversion for 3rd conditional. Omits "if" by inverting.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d51-t017', hindi:'Subjunctive: "It is important that he ___ on time."', options:['is','be','was','will be'], correct:1, explanation:'"It is important that he be on time." — Subjunctive mood. No "s" on verb, use "be" not "is."', type:'fill-blank', difficulty:'hard', marks:3 },
  { id:'d51-t018', hindi:'"I wish she ___ here right now." (she is not here)', options:['is','was/were','has been','will be'], correct:1, explanation:'"I wish she were here right now." — Wish + subjunctive (past form). "Were" preferred even for she.', type:'fill-blank', difficulty:'hard', marks:3 },
  { id:'d51-t019', hindi:'Concession: "Much as I like her, I can\'t agree." — "much as" meaning:', options:['Although','Very much','Despite much','Because'], correct:0, explanation:'"Much as I like her" = although I like her very much. Formal concession.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d51-t020', hindi:'"The harder I try, the better I get." — "the...the" structure:', options:['Comparison showing proportional relationship','Two separate sentences','Question form','Conditional'], correct:0, explanation:'"The + comparative, the + comparative" = proportional relationship. Both change together.', type:'mcq', difficulty:'hard', marks:3 },
]);

const DAY_52_TEST = createAdvancedTest(52, 'Advance Level Sentences Part 2', [
  { id:'d52-t001', hindi:'Participle phrase: "Having finished the work, she left."', options:['Having finished = past participle phrase as adverbial','Having finished = subject','She = past participle','Work = participle'], correct:0, explanation:'"Having finished the work" = perfect participle phrase. Shows action completed before main verb.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d52-t002', hindi:'"Exhausted by the race, he sat down." — structure:', options:['Past participle phrase (exhausted) used as adverbial modifier','Simple sentence','Compound','Question'], correct:0, explanation:'"Exhausted by the race" = past participle phrase modifying "he." Condensed adverbial clause.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d52-t003', hindi:'Gerund as subject: "___ is good for health."', options:['To exercise','Exercise','Exercising / Exercise (both correct)','Exercised'], correct:2, explanation:'"Exercising is good for health." or "Exercise is good for health." — gerund or bare noun as subject.', type:'mcq', difficulty:'medium', marks:2 },
  { id:'d52-t004', hindi:'Gerund vs Infinitive after "remember":', options:['Always gerund','Always infinitive','Remember + Ving = past memory; Remember + to + V1 = future task','No difference'], correct:2, explanation:'"I remember locking the door." (past memory). "Remember to lock the door." (don\'t forget future task).', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d52-t005', hindi:'"Stop + Ving" vs "Stop + to + V1":',options:['Same meaning','Stop + Ving = quit doing; Stop + to + V1 = pause in order to do something else','Stop + to = quit; Stop + Ving = pause','No difference'], correct:1, explanation:'"He stopped smoking." (quit). "He stopped to smoke." (paused his walk in order to smoke).', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d52-t006', hindi:'Inversion after "Rarely": "Rarely ___ such talent."', options:['we see','do we see','we do see','did we see'], correct:1, explanation:'"Rarely do we see such talent." — negative adverb inversion: Rarely + auxiliary + subject.', type:'fill-blank', difficulty:'hard', marks:3 },
  { id:'d52-t007', hindi:'Inversion after "Only then": "Only then ___ the truth."', options:['he realized','did he realize','he did realize','he has realized'], correct:1, explanation:'"Only then did he realize the truth." — "Only + adverb/phrase" at front = inversion.', type:'fill-blank', difficulty:'hard', marks:3 },
  { id:'d52-t008', hindi:'Ellipsis: "She can play the piano, and he ___ too."', options:['can','can play','can play the piano','can too'], correct:0, explanation:'"He can too." — Ellipsis: "can play the piano" is omitted. Just "can" remains.', type:'fill-blank', difficulty:'hard', marks:3 },
  { id:'d52-t009', hindi:'Fronting for emphasis: "This film I loved."', options:['Error — wrong word order','Correct — fronting object for emphasis','Only in questions','Passive voice'], correct:1, explanation:'"This film I loved." — fronting object "this film" for emphasis. Informal but correct.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d52-t010', hindi:'"It goes without saying that ___." — meaning:', options:['It should be said','यह तो सबको पता है / it is obvious/well-known','It is strange that','Say without words'], correct:1, explanation:'"It goes without saying" = it is obvious / well-known fact. No need to say explicitly.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d52-t011', hindi:'Parallel structure error: "She likes swimming, running, and to cycle."', options:['No error','Error — should be "cycling" for parallel structure','Error in "running"','Error in "swimming"'], correct:1, explanation:'"To cycle" breaks parallel structure. Should be "cycling" to match swimming and running.', type:'error-detection', difficulty:'hard', marks:3 },
  { id:'d52-t012', hindi:'"The more you practice, ___" — complete using "the better" pattern:', options:['the more better you become','the better you become','you become better','better you are'], correct:1, explanation:'"The more you practice, the better you become." — "the + comparative, the + comparative" structure.', type:'fill-blank', difficulty:'medium', marks:2 },
  { id:'d52-t013', hindi:'Dangling modifier error: "Walking down the street, the rain started."', options:['No error','Error — "the rain" can\'t walk. Should be "Walking down the street, I got caught in the rain."','Error in "started"','Error in "the street"'], correct:1, explanation:'Dangling modifier: "Walking down the street" should modify a person, not "the rain."', type:'error-detection', difficulty:'hard', marks:3 },
  { id:'d52-t014', hindi:'Emphatic "do": "She ___ help me yesterday, even though I doubted her."', options:['did','does','was','would'], correct:0, explanation:'"She did help me yesterday." — emphatic "did" for stress/contrast. Stresses that she actually helped.', type:'fill-blank', difficulty:'hard', marks:3 },
  { id:'d52-t015', hindi:'Identify the compound-complex sentence:', options:['She left.','She left and he stayed.','She left because she was tired, and he stayed to finish the work.','Although she left.'], correct:2, explanation:'"She left because she was tired (complex), and he stayed to finish the work (compound)." = Compound-Complex.', type:'mcq', difficulty:'medium', marks:2 },
  { id:'d52-t016', hindi:'"Not until she left did he realize ___." — structure:', options:['Normal declarative','Inverted sentence with "not until" for emphasis','Question','Passive'], correct:1, explanation:'"Not until + clause + inversion." Formal emphasis structure.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d52-t017', hindi:'Appositive: "My best friend, ___ engineer, lives in Bangalore."', options:['the','a','an','no article'], correct:2, explanation:'"My best friend, an engineer, lives in Bangalore." — "an" before vowel sound "en."', type:'fill-blank', difficulty:'medium', marks:2 },
  { id:'d52-t018', hindi:'"Scarcely had he spoken when ___." — time meaning:', options:['After a long time','Immediately after (as soon as)','Before','While'], correct:1, explanation:'"Scarcely had he spoken when" = as soon as he spoke / almost immediately after.', type:'mcq', difficulty:'hard', marks:3 },
  { id:'d52-t019', hindi:'Tag question: "She has finished, ___ she?"', options:['has','hasn\'t','haven\'t','didn\'t'], correct:1, explanation:'"She has finished, hasn\'t she?" — Positive main clause → negative tag. "has" → "hasn\'t."', type:'fill-blank', difficulty:'medium', marks:2 },
  { id:'d52-t020', hindi:'Complete sentence review: Most advanced sentence type:',options:['Simple (one clause)','Compound (two independent)','Complex (main + subordinate)','Compound-Complex (2+ independent + 1+ subordinate)'], correct:3, explanation:'Compound-Complex is the most structurally complex type with multiple clause types.', type:'mcq', difficulty:'easy', marks:1 },
]);

